using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> size;
    long long components;

public:
    UnionFind(long long n) : components(n) {
        parent.resize(n);
        size.resize(n, 1);
        iota(parent.begin(), parent.end(), 0);
    }

    long long find(long long u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    void unite(long long u, long long v) {
        long long rootU = find(u);
        long long rootV = find(v);
        if (rootU != rootV) {
            if (size[rootU] < size[rootV]) {
                swap(rootU, rootV);
            }
            parent[rootV] = rootU;
            size[rootU] += size[rootV];
            components--;
        }
    }

    long long getComponents() const {
        return components;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (k <= 1) return 0;
    if (n < k) return -1; // Not possible, but problem says k <= n

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    long long low = 0;
    long long high = 1e18;
    long long answer = 0;

    // Check if initial components are already >= k
    if (uf.getComponents() >= k) {
        return 0;
    }

    // Binary search for the minimal t
    while (low <= high) {
        long long mid = low + (high - low) / 2;
        UnionFind tempUF(n);

        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                tempUF.unite(edge[0], edge[1]);
            }
        }

        if (tempUF.getComponents() >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

